// GetTrimmedLogo returns NewSmallPixelLines without leading/trailing empty lines.
func GetTrimmedLogo() []string {
	var out []string
	for _, line := range NewSmallPixelLines {
		if strings.TrimSpace(line) != "" {
			out = append(out, line)
		}
	}
	return out
}
